package main

import (
	"errors"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// TestCheckAgainstCommitted covers the user-facing outcomes: matched, drift,
// missing committed file, source-hash changes, and orphan generated files. Uses
// tmpdir fixtures so we don't have to edit the real committed copies.
func TestCheckAgainstCommitted(t *testing.T) {
	const header = "// Code generated by twitch-api-gen. DO NOT EDIT.\n// Source: https://example.test/\n// Source-Hash: %s\n\npackage twitch\n"

	t.Run("match", func(t *testing.T) {
		gen := t.TempDir()
		committed := t.TempDir()
		for _, name := range checkedFiles {
			writeFile(t, filepath.Join(gen, name), []byte(render(header, "abc123")))
			writeFile(t, filepath.Join(committed, name), []byte(render(header, "abc123")))
		}
		if err := checkAgainstCommitted(gen, committed, silentLogger()); err != nil {
			t.Fatalf("expected nil; got %v", err)
		}
	})

	t.Run("drift reports stale files", func(t *testing.T) {
		gen := t.TempDir()
		committed := t.TempDir()
		for _, name := range checkedFiles {
			writeFile(t, filepath.Join(gen, name), []byte(render(header, "t")+"added line\n"))
			writeFile(t, filepath.Join(committed, name), []byte(render(header, "t")))
		}
		err := checkAgainstCommitted(gen, committed, silentLogger())
		if err == nil {
			t.Fatalf("expected drift error")
		}
		if !errors.Is(err, ErrGeneratedFilesStale) {
			t.Errorf("err %v: want wrapping ErrGeneratedFilesStale", err)
		}
		for _, name := range checkedFiles {
			if !strings.Contains(err.Error(), name) {
				t.Errorf("drift message should name %s; got %q", name, err.Error())
			}
		}
	})

	t.Run("missing committed file counts as drift", func(t *testing.T) {
		gen := t.TempDir()
		committed := t.TempDir()
		for _, name := range checkedFiles {
			writeFile(t, filepath.Join(gen, name), []byte(render(header, "t")))
		}
		// committed dir is empty — every file is "missing"
		err := checkAgainstCommitted(gen, committed, silentLogger())
		if err == nil {
			t.Fatalf("expected drift error")
		}
		if !errors.Is(err, ErrGeneratedFilesStale) {
			t.Errorf("err %v: want wrapping ErrGeneratedFilesStale", err)
		}
		if !strings.Contains(err.Error(), "committed file missing") {
			t.Errorf("drift message should mention missing files; got %q", err.Error())
		}
	})

	t.Run("source hash drift counts as stale", func(t *testing.T) {
		gen := t.TempDir()
		committed := t.TempDir()
		for _, name := range checkedFiles {
			writeFile(t, filepath.Join(gen, name), []byte(render(header, "new-hash")))
			writeFile(t, filepath.Join(committed, name), []byte(render(header, "old-hash")))
		}
		err := checkAgainstCommitted(gen, committed, silentLogger())
		if err == nil {
			t.Fatalf("expected drift error for changed source hash")
		}
		if !errors.Is(err, ErrGeneratedFilesStale) {
			t.Errorf("err %v: want wrapping ErrGeneratedFilesStale", err)
		}
	})

	t.Run("orphan committed generated file counts as drift", func(t *testing.T) {
		gen := t.TempDir()
		committed := t.TempDir()
		for _, name := range checkedFiles {
			writeFile(t, filepath.Join(gen, name), []byte(render(header, "t")))
			writeFile(t, filepath.Join(committed, name), []byte(render(header, "t")))
		}
		writeFile(t, filepath.Join(committed, "generated_legacy.go"), []byte(render(header, "t")))

		err := checkAgainstCommitted(gen, committed, silentLogger())
		if err == nil {
			t.Fatalf("expected drift error for orphan generated file")
		}
		if !errors.Is(err, ErrGeneratedFilesStale) {
			t.Errorf("err %v: want wrapping ErrGeneratedFilesStale", err)
		}
		if !strings.Contains(err.Error(), "generated_legacy.go") {
			t.Errorf("drift message should mention orphan file; got %q", err.Error())
		}
	})
}

func writeFile(t *testing.T, path string, data []byte) {
	t.Helper()
	if err := os.WriteFile(path, data, 0o644); err != nil {
		t.Fatalf("write %s: %v", path, err)
	}
}

func render(format, hash string) string {
	return strings.Replace(format, "%s", hash, 1)
}
